document.addEventListener('DOMContentLoaded',function(){const menuToggle=document.querySelector('.menu-toggle');const mainNav=document.querySelector('.main-nav');if(menuToggle&&mainNav){menuToggle.addEventListener('click',function(){mainNav.classList.toggle('is-open');});}document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){e.preventDefault();const target=document.querySelector(this.getAttribute('href'));if(target){target.scrollIntoView({behavior: 'smooth'});}});});document.querySelectorAll('a[target="_blank"]').forEach(link=>{if(!link.querySelector('.external-icon')){link.innerHTML+='<span class="external-icon">↗</span>';}});console.log('ZeroPress theme loaded');});